import os
import boto3

def get_latest_model_version(model_path):
    s3 = boto3.client('s3')
    bucket_name, prefix = model_path.replace("s3://", "").split('/', 1)
    response = s3.list_objects_v2(Bucket=bucket_name, Prefix=prefix)
    all_versions = [obj['Key'] for obj in response.get('Contents', [])]
    latest_model = max(all_versions, key=lambda x: x.split('/')[-1])
    return latest_model

def load_model_from_s3(model_key):
    s3 = boto3.client('s3')
    bucket_name = model_key.split('/')[0]
    model_file = model_key.split('/', 1)[1]
    download_path = '/tmp/model_file'
    s3.download_file(bucket_name, model_file, download_path)
    return download_path

def main():
    model_path = os.getenv('MODEL_PATH')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable is not set")

    latest_model_version = get_latest_model_version(model_path)
    model_location = load_model_from_s3(latest_model_version)

    print(f"Model loaded from: {model_location}")
    # Add code to load the model into memory, depending on your ML framework

if __name__ == "__main__":
    main()